60: func (key ConfigKey) HashCode() uint64 {
61: 	hash := md5.New()
62: 	for _, v := range []string{
63: 		key.Name,
64: 		key.Namespace,
65: 		key.Kind.Kind,
66: 		key.Kind.Group,
67: 		key.Kind.Version,
68: 	} {
69: 		hash.Write([]byte(v))
70: 	}
